mapper.insert:
/** UsptStdntMtchDao.insert */
insert into uspt_stdnt_mtch
	(
		last_slctn_trget_id
		, apply_id
		, creator_id
		, created_dt
	) values (
		#{lastSlctnTrgetId}
		, #{applyId}
		, #{creatorId}
		, #{createdDt}
	)

mapper.delete:
/** UsptStdntMtchDao.delete */
delete from uspt_stdnt_mtch
where
	last_slctn_trget_id = #{lastSlctnTrgetId}
	and apply_id = #{applyId}

mapper.select:
/** UsptStdntMtchDao.selectMtchStdnListCount */
select
	count(usm.apply_id)
from uspt_stdnt_mtch usm
where
	usm.last_slctn_trget_id = #{lastSlctnTrgetId}
